      "linear-gradient(180deg, rgba(167,139,250,0.10) 0%, rgba(167,139,250,0.55) 100%)",
  },
  {
    code: "POKEMON",
    display: "Pok\u00e9mon",
    shortName: "PKMN",
    image: "/images/card-backs/Back_of_pokemon_card.webp",
    bgGradient: "linear-gradient(135deg, #1a1a08 0%, #3d3000 100%)",
    overlayGradient:
      "linear-gradient(180deg, rgba(252,211,77,0.08) 0%, rgba(252,211,77,0.50) 100%)",
  },
  {
    code: "YUGIOH",
    display: "Yu-Gi-Oh!",
    shortName: "YGO",
    image: "/images/card-backs/Back_of_Yu-Gi-Oh_card.webp",
    bgGradient: "linear-gradient(135deg, #081a30 0%, #0d2b5e 100%)",
    overlayGradient:
      "linear-gradient(180deg, rgba(96,165,250,0.10) 0%, rgba(96,165,250,0.55) 100%)",
  },
  {
    code: "OPTCG",
    display: "One Piece",
