interface GameSelectorGridProps {
  counts?: Record<string, number>
}

export function GameSelectorGrid({ counts }: GameSelectorGridProps) {
  return (
    <section className="px-5 py-[40px] sm:px-12 sm:py-[64px]">
      <div className="mx-auto max-w-[1344px]">
        <p className="mb-7 text-[11px] font-semibold uppercase tracking-[0.12em] text-tertiary font-barlow">
          Shop by Game
        </p>
        <div className="grid grid-cols-2 gap-3 md:grid-cols-4 md:gap-4">
          {GAMES.map((game) => (
            <GameTile
              key={game.code}
              code={game.code}
              display={game.display}
              image={game.image}
              bgGradient={game.bgGradient}
              overlayGradient={game.overlayGradient}
              count={counts?.[game.code]}
            />
          ))}
        </div>
      </div>
    </section>
  )
}

"use client"

import { useHits, useStats, useInstantSearch, useCurrentRefinements, usePagination } from "react-instantsearch"
import { SearchResultsSkeleton } from "./SearchResultsSkeleton"
import { SearchNoResults } from "./SearchNoResults"
import { SearchFilteredNoResults } from "./SearchFilteredNoResults"
import { SearchFilters } from "./SearchFilters"
import { AlgoliaCardHit } from "@/components/cards/AlgoliaCardHit"
import type { AlgoliaHit } from "@/components/cards/AlgoliaCardHit"

// ─── Pagination sub-component ──────────────────────────────────────────────────

function CardPagination() {
  const { currentRefinement, nbPages, nbHits, refine, isFirstPage, isLastPage } = usePagination()
  const hitsPerPage = 20

  if (nbPages <= 1) return null

  const currentPage = currentRefinement // 0-indexed
  const startItem = currentPage * hitsPerPage + 1
  const endItem = Math.min((currentPage + 1) * hitsPerPage, nbHits)

  // Build visible page numbers with ellipsis
  const getVisiblePages = (): (number | "...")[] => {
    const pages: (number | "...")[] = []
    const delta = 2
    const total = nbPages

    pages.push(0) // always first page

    const start = Math.max(1, currentPage - delta)
    const end = Math.min(total - 2, currentPage + delta)

    if (start > 1) pages.push("...")
    for (let i = start; i <= end; i++) pages.push(i)
    if (end < total - 2) pages.push("...")

    if (total > 1) pages.push(total - 1) // always last page

    return pages
  }

  return (
    <div
      data-testid="pagination"
      style={{
        padding: "32px 24px 40px",
        display: "flex",
        flexDirection: "column",
        alignItems: "center",
        gap: 12,
      }}
    >
      {/* Showing X–Y of Z results */}
      <div
        style={{
          fontSize: 12,
          color: "var(--text-tertiary, #7B72A8)",
        }}
      >
        Showing {startItem.toLocaleString()}–{endItem.toLocaleString()} of{" "}
        {nbHits.toLocaleString()} results
      </div>

      {/* Page buttons */}
      <div
        style={{
          display: "flex",
          alignItems: "center",
          gap: 4,
        }}
      >
        {/* Previous arrow */}
        <button
          onClick={() => refine(currentPage - 1)}
          disabled={isFirstPage}
          aria-label="Previous page"
          style={{
            minWidth: 34,
            height: 34,
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            borderRadius: 6,
            fontSize: 14,
            fontWeight: 500,
            color: isFirstPage
              ? "var(--border-default, #2C2A4A)"
              : "var(--text-tertiary, #7B72A8)",
            background: "transparent",
            border: "1px solid transparent",
            cursor: isFirstPage ? "default" : "pointer",
            fontFamily: "var(--font-body, 'Inter', sans-serif)",
          }}
        >
          «
        </button>

        {getVisiblePages().map((page, idx) => {
          if (page === "...") {
            return (
              <span
                key={`dots-${idx}`}
                style={{
                  fontSize: 13,
                  color: "var(--text-tertiary, #7B72A8)",
                  padding: "0 4px",
                }}
              >
                …
              </span>
            )
          }

          const isActive = page === currentPage

          return (
            <button
              key={page}
              onClick={() => refine(page)}
              aria-label={`Page ${page + 1}`}
              aria-current={isActive ? "page" : undefined}
              style={{
                minWidth: 34,
                height: 34,
                display: "flex",
                alignItems: "center",
                justifyContent: "center",
                borderRadius: 6,
                fontSize: 13,
                fontWeight: isActive ? 600 : 500,
                color: isActive ? "#fff" : "var(--text-secondary, #B8B0D8)",
                background: isActive
                  ? "var(--brand-primary, #8B5CF6)"
                  : "transparent",
                border: isActive
                  ? "1px solid var(--brand-primary, #8B5CF6)"
                  : "1px solid transparent",
                cursor: "pointer",
                fontFamily: "var(--font-body, 'Inter', sans-serif)",
              }}
            >
              {page + 1}
            </button>
          )
        })}

        {/* Next arrow */}
        <button
          onClick={() => refine(currentPage + 1)}
          disabled={isLastPage}
          aria-label="Next page"
          style={{
            minWidth: 34,
            height: 34,
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            borderRadius: 6,
            fontSize: 14,
            fontWeight: 500,
            color: isLastPage
              ? "var(--border-default, #2C2A4A)"
              : "var(--text-tertiary, #7B72A8)",
            background: "transparent",
            border: "1px solid transparent",
            cursor: isLastPage ? "default" : "pointer",
            fontFamily: "var(--font-body, 'Inter', sans-serif)",
          }}
        >
          »
        </button>
      </div>
    </div>
  )
}

// ─── CardSearchGrid ────────────────────────────────────────────────────────────

/**
 * Shared sidebar + card grid layout with numbered pagination.
 * Renders the SearchFilters sidebar (280px) and the card hit grid (flex-1).
 * Used by both CardBrowsingPage and the search page.
 */
interface CardSearchGridProps {
  viewMode?: "grid" | "list"
}

export function CardSearchGrid({ viewMode = "grid" }: CardSearchGridProps) {
  const { items: hits } = useHits<AlgoliaHit>()
  const { nbHits, query } = useStats()
  const { status, results } = useInstantSearch()
  const { items: refinementItems } = useCurrentRefinements()

  const activeFilterCount = refinementItems.reduce((sum, item) => sum + item.refinements.length, 0)
  const hasActiveFilters = activeFilterCount > 0

  const isLoading = status === "loading" || status === "stalled"
  const isInitialLoading = isLoading && hits.length === 0
  const isNoResults = !isLoading && nbHits === 0

  return (
    <div
      data-testid="card-search-grid"
      style={{ display: "flex", minHeight: 900 }}
    >
      {/* Desktop sidebar — always mounted, hidden on mobile via SearchFilters internal responsive logic */}
      <SearchFilters activeFilterCount={activeFilterCount} />

      {/* Main content */}
      <div style={{ flex: 1, minWidth: 0, padding: "20px 24px" }}>
        {isInitialLoading ? (
          <SearchResultsSkeleton />
        ) : isNoResults ? (
          hasActiveFilters ? (
            <SearchFilteredNoResults
              onClearFilters={() => {
                setTimeout(() => {
                  for (const item of refinementItems) {
                    for (const refinement of item.refinements) {
                      item.refine(refinement)
                    }
                  }
                }, 0)
              }}
            />
          ) : (
            <SearchNoResults query={query} queryAfterRemoval={results?.queryAfterRemoval} />
          )
        ) : (
          <>
            {/* Card grid — 4-col → 3 @ 1024px → 2 @ 640px; list = 1-col */}
            <div
              data-testid="card-grid"
              data-view={viewMode}
              className="grid gap-4"
              style={{
                gridTemplateColumns: viewMode === "list"
                  ? "1fr"
                  : "repeat(4, 1fr)",
              }}
            >
              <style>{`
                @media (max-width: 1024px) {
                  [data-testid="card-grid"]:not([data-view="list"]) { grid-template-columns: repeat(3, 1fr) !important; }
                }
                @media (max-width: 640px) {
                  [data-testid="card-grid"]:not([data-view="list"]) {
                    grid-template-columns: repeat(2, 1fr) !important;
                    gap: 10px !important;
                    padding: 0 12px;
                  }
                }
              `}</style>
              {hits.map((hit) => (
                <AlgoliaCardHit key={hit.objectID} hit={hit} variant={viewMode} />
              ))}
            </div>

            {/* Numbered pagination */}
            <CardPagination />
          </>
        )}
      </div>
    </div>
  )
}

"use client"

import { useRefinementList } from "react-instantsearch"

// ─── Game data ─────────────────────────────────────────────────────────────────

export const GAME_STRIP_ITEMS = [
  {
    code: null as string | null,
    display: "All Games",
    shortName: "All",
    bgGradient: "linear-gradient(135deg, #1a103a 0%, #2a1a4a 50%, #1a2030 100%)",
    overlayGradient: "linear-gradient(180deg, rgba(139,92,246,0.08) 0%, rgba(139,92,246,0.45) 100%)",
    activeClass: "all" as const,
    borderColor: "var(--brand-primary, #8B5CF6)",
    glowColor: "rgba(139, 92, 246, 0.25)",
    dotColor: "var(--brand-primary, #8B5CF6)",
  },
  {
    code: "MTG",
    display: "Magic: The Gathering",
    shortName: "MTG",
    bgGradient: "linear-gradient(135deg, #1a103a 0%, #2d1b69 100%)",
    overlayGradient: "linear-gradient(180deg, rgba(167,139,250,0.08) 0%, rgba(167,139,250,0.50) 100%)",
    activeClass: "mtg" as const,
    borderColor: "var(--game-mtg, #A78BFA)",
    glowColor: "rgba(167, 139, 250, 0.25)",
    dotColor: "var(--game-mtg, #A78BFA)",
  },
  {
    code: "POKEMON",
    display: "Pokémon",
    shortName: "PKMN",
    bgGradient: "linear-gradient(135deg, #1a1a08 0%, #3d3000 100%)",
    overlayGradient: "linear-gradient(180deg, rgba(252,211,77,0.06) 0%, rgba(252,211,77,0.45) 100%)",
    activeClass: "poke" as const,
    borderColor: "var(--game-pokemon, #FCD34D)",
    glowColor: "rgba(252, 211, 77, 0.25)",
    dotColor: "var(--game-pokemon, #FCD34D)",
  },
  {
    code: "YUGIOH",
    display: "Yu-Gi-Oh!",
    shortName: "YGO",
    bgGradient: "linear-gradient(135deg, #081a30 0%, #0d2b5e 100%)",
    overlayGradient: "linear-gradient(180deg, rgba(96,165,250,0.08) 0%, rgba(96,165,250,0.50) 100%)",
    activeClass: "ygo" as const,
    borderColor: "var(--game-ygo, #60A5FA)",
    glowColor: "rgba(96, 165, 250, 0.25)",
    dotColor: "var(--game-ygo, #60A5FA)",
  },
  {
    code: "OPTCG",
    display: "One Piece",
    shortName: "OP",
    bgGradient: "linear-gradient(135deg, #081a14 0%, #0d3d2b 100%)",
    overlayGradient: "linear-gradient(180deg, rgba(52,211,153,0.06) 0%, rgba(52,211,153,0.45) 100%)",
    activeClass: "op" as const,
    borderColor: "var(--game-op, #34D399)",
    glowColor: "rgba(52, 211, 153, 0.25)",
    dotColor: "var(--game-op, #34D399)",
  },
] as const

// ─── Cookie helper ─────────────────────────────────────────────────────────────

function setGameCookie(code: string | null) {
  try {
    const secure = location.protocol === "https:" ? "; Secure" : ""
    if (code === null) {
      // Clear cookie for "All Games"
      document.cookie = `sd_game_pref=; max-age=0; path=/; SameSite=Lax${secure}`
    } else {
      document.cookie = `sd_game_pref=${encodeURIComponent(code)}; max-age=2592000; path=/; SameSite=Lax${secure}`
    }
  } catch {
    // Best-effort
  }
}

// ─── Component ─────────────────────────────────────────────────────────────────

export function GameSelectorStrip() {
  const { items, refine } = useRefinementList({ attribute: "game" })

  // Determine which game is currently selected via the Algolia refinement
  const activeRefinements = items.filter((i) => i.isRefined).map((i) => i.value)
  // Single game selected means that game is active; no selection = "All Games"
  const activeGameCode = activeRefinements.length === 1 ? activeRefinements[0] : null

  function handleSelect(code: string | null) {
    // Clear any existing game refinements first
    for (const item of items) {
      if (item.isRefined) {
        refine(item.value)
      }
    }
    // Then set the new one (if not "All Games")
    if (code !== null) {
      // Need to wait for clears to process, then apply new refinement
      // Since refine is synchronous in its state update, we can call it right after
      refine(code)
    }
    setGameCookie(code)
  }

  return (
    <div style={{ padding: "24px 32px 0" }}>
      {/* Desktop: 5-column grid */}
      <div
        className="hidden md:grid"
        data-testid="game-strip-desktop"
        style={{
          gridTemplateColumns: "repeat(5, 1fr)",
          gap: 12,
        }}
      >
        {GAME_STRIP_ITEMS.map((game) => {
          const isActive = game.code === activeGameCode
          return (
            <button
              key={game.code ?? "all"}
              data-testid={`game-strip-${game.code ?? "all"}`}
              onClick={() => handleSelect(game.code)}
              aria-pressed={isActive}
              aria-label={game.display}
              style={{
                position: "relative",
                borderRadius: 12,
                overflow: "hidden",
                aspectRatio: "16 / 7",
                cursor: "pointer",
                transition: "transform 0.2s, box-shadow 0.2s",
                border: isActive
                  ? `2px solid ${game.borderColor}`
                  : "2px solid transparent",
                boxShadow: isActive
                  ? `0 0 20px ${game.glowColor}`
                  : "none",
                background: "transparent",
                padding: 0,
                textAlign: "left",
              }}
            >
              {/* Background gradient */}
              <div
                style={{
                  position: "absolute",
                  inset: 0,
                  background: game.bgGradient,
                }}
              >
                <div
                  style={{
                    position: "absolute",
                    inset: 0,
                    backgroundImage:
                      "radial-gradient(circle at 30% 30%, rgba(255,255,255,0.03) 0%, transparent 60%), radial-gradient(circle at 70% 60%, rgba(255,255,255,0.02) 0%, transparent 50%)",
                  }}
                />
              </div>
              {/* Overlay with name + count */}
              <div
                style={{
                  position: "absolute",
                  inset: 0,
                  display: "flex",
                  flexDirection: "column",
