                    fontSize: 11,
                    color: "rgba(255, 255, 255, 0.7)",
                  }}
                >
                  {/* Count from Algolia facets */}
                  {game.code === null
                    ? `${items.reduce((sum, i) => sum + i.count, 0).toLocaleString()} cards`
                    : `${items.find((i) => i.value === game.code)?.count?.toLocaleString() ?? "0"} cards`}
                </span>
              </div>
            </button>
          )
        })}
      </div>

      {/* Mobile: horizontal pill scroll */}
      <div
        className="flex md:hidden gap-2 overflow-x-auto pb-1"
        data-testid="game-strip-mobile"
        style={{ scrollbarWidth: "none" }}
      >
        {GAME_STRIP_ITEMS.map((game) => {
          const isActive = game.code === activeGameCode
          return (
            <button
              key={game.code ?? "all"}
              data-testid={`game-pill-${game.code ?? "all"}`}
              onClick={() => handleSelect(game.code)}
              aria-pressed={isActive}
              style={{
                flexShrink: 0,
                display: "flex",
                alignItems: "center",
                gap: 6,
                padding: "6px 14px",
                borderRadius: 999,
                border: isActive
                  ? `1px solid var(--brand-primary, #8B5CF6)`
                  : "1px solid var(--border-default, #2C2A4A)",
                background: isActive
                  ? "rgba(139, 92, 246, 0.12)"
                  : "var(--bg-surface-2, #21203A)",
                fontFamily: "var(--font-heading, 'Barlow', sans-serif)",
                fontSize: 12,
                fontWeight: 600,
                color: isActive
                  ? "var(--brand-primary, #8B5CF6)"
                  : "var(--text-secondary, #B8B0D8)",
                cursor: "pointer",
                whiteSpace: "nowrap",
              }}
            >
              <span
                style={{
                  width: 8,
                  height: 8,
                  borderRadius: "50%",
                  background: game.dotColor,
                  flexShrink: 0,
                }}
              />
              {game.shortName}
            </button>
          )
        })}
      </div>
    </div>
  )
}

"use client"

import { useState, useCallback } from "react"
import { useRange } from "react-instantsearch"

// ─── Category definitions ──────────────────────────────────────────────────────

interface Category {
  label: string
  /** What filter action this pill triggers */
  action: "all" | "price-under-5" | "unimplemented"
}

const CATEGORIES: Category[] = [
  { label: "All", action: "all" },
  { label: "New Releases", action: "unimplemented" },
  { label: "Trending", action: "unimplemented" },
  { label: "Under $5", action: "price-under-5" },
  { label: "Staples", action: "unimplemented" },
  { label: "Format Legal", action: "unimplemented" },
  { label: "Foils & Special", action: "unimplemented" },
]

// ─── Component ─────────────────────────────────────────────────────────────────

export function CategoryPills() {
  const [activeLabel, setActiveLabel] = useState("All")
  const { start, refine: refineRange } = useRange({ attribute: "lowest_price" })

  const handleClick = useCallback(
    (category: Category) => {
      setActiveLabel(category.label)

      switch (category.action) {
        case "all":
          // Clear price range filter
          refineRange([undefined as unknown as number, undefined as unknown as number])
          break

        case "price-under-5":
          // Filter to cards with price 0–5
          refineRange([0, 5])
          break

        case "unimplemented":
          // No backend facet available yet — visual selection only
          break
      }
    },
    [refineRange]
  )

  return (
    <div style={{ padding: "16px 32px 0" }}>
      <div
        className="flex gap-2 overflow-x-auto pb-1"
        data-testid="category-pills"
        style={{
          scrollbarWidth: "thin",
          scrollbarColor: "var(--bg-surface-3, #2C2A4A) transparent",
        }}
      >
        {CATEGORIES.map((cat) => {
          const isActive = activeLabel === cat.label
          return (
            <button
              key={cat.label}
              data-testid={`category-pill-${cat.label.toLowerCase().replace(/[^a-z0-9]/g, "-")}`}
              onClick={() => handleClick(cat)}
              style={{
                flexShrink: 0,
                fontFamily: "var(--font-heading, 'Barlow', sans-serif)",
                fontSize: 13,
                fontWeight: 600,
                padding: "6px 18px",
                borderRadius: 999,
                border: isActive
                  ? "1px solid var(--brand-primary, #8B5CF6)"
                  : "1px solid var(--border-default, #2C2A4A)",
                background: isActive
                  ? "rgba(139, 92, 246, 0.12)"
                  : "transparent",
                color: isActive
                  ? "var(--brand-primary, #8B5CF6)"
                  : "var(--text-secondary, #B8B0D8)",
                cursor: "pointer",
                transition: "all 0.15s",
                whiteSpace: "nowrap",
              }}
            >
              {cat.label}
            </button>
          )
        })}
      </div>
    </div>
  )
}

