  /** Current game code from GameSelectorStrip. null = All Games */
  gameCode: string | null
}

export function PopularSetsCarousel({ gameCode }: PopularSetsCarouselProps) {
  const { refine, items: refinedItems } = useRefinementList({ attribute: "set_name" })
  const refinedValues = new Set(refinedItems.filter((i) => i.isRefined).map((i) => i.value))

