"use client"

import { useState } from "react"
import { useStats } from "react-instantsearch"
import { ActiveFilterChips } from "@/components/search/ActiveFilterChips"
import { SortControl } from "@/components/search/SortControl"

// ─── View mode type ────────────────────────────────────────────────────────────

export type ViewMode = "grid" | "list"

interface ResultsBarProps {
  viewMode?: ViewMode
  onViewModeChange?: (mode: ViewMode) => void
}

// ─── Grid/List icons (inline SVG for small footprint) ──────────────────────────

function GridIcon() {
  return (
    <svg width="14" height="14" viewBox="0 0 14 14" fill="none" xmlns="http://www.w3.org/2000/svg">
      <rect x="1" y="1" width="5" height="5" rx="1" fill="currentColor" />
      <rect x="8" y="1" width="5" height="5" rx="1" fill="currentColor" />
      <rect x="1" y="8" width="5" height="5" rx="1" fill="currentColor" />
      <rect x="8" y="8" width="5" height="5" rx="1" fill="currentColor" />
    </svg>
  )
}

function ListIcon() {
  return (
    <svg width="14" height="14" viewBox="0 0 14 14" fill="none" xmlns="http://www.w3.org/2000/svg">
      <rect x="1" y="1.5" width="12" height="2.5" rx="1" fill="currentColor" />
      <rect x="1" y="5.75" width="12" height="2.5" rx="1" fill="currentColor" />
      <rect x="1" y="10" width="12" height="2.5" rx="1" fill="currentColor" />
    </svg>
  )
}

// ─── Component ─────────────────────────────────────────────────────────────────

export function ResultsBar({ viewMode: controlledMode, onViewModeChange }: ResultsBarProps) {
  const [internalMode, setInternalMode] = useState<ViewMode>("grid")
  const { nbHits } = useStats()

  const mode = controlledMode ?? internalMode
  const setMode = (m: ViewMode) => {
    setInternalMode(m)
    onViewModeChange?.(m)
  }

  return (
    <div
      data-testid="results-bar"
      style={{
        display: "flex",
        alignItems: "center",
        justifyContent: "space-between",
        padding: "14px 32px",
        background: "var(--bg-base, #09090F)",
        borderBottom: "1px solid var(--border-default, #2C2A4A)",
        borderTop: "1px solid var(--border-default, #2C2A4A)",
        marginTop: 20,
      }}
    >
      {/* Left: filter chips + results count */}
      <div
        style={{
          display: "flex",
          alignItems: "center",
          gap: 10,
          flexWrap: "wrap",
          flex: 1,
          minWidth: 0,
        }}
      >
        <ActiveFilterChips />
        <span
          style={{
            fontSize: 13,
            color: "var(--text-secondary, #B8B0D8)",
            flexShrink: 0,
          }}
        >
          <strong
            style={{
              color: "var(--text-primary, #F0EEFF)",
              fontWeight: 600,
            }}
          >
            {nbHits.toLocaleString()}
          </strong>{" "}
          results
        </span>
      </div>

      {/* Right: view toggle + sort */}
      <div
        className="hidden md:flex"
        style={{
          alignItems: "center",
          gap: 16,
          flexShrink: 0,
          marginLeft: 16,
        }}
      >
        {/* View toggle (grid/list) */}
        <div
          data-testid="view-toggle"
          style={{
            display: "flex",
            background: "var(--bg-surface-2, #21203A)",
            borderRadius: "var(--radius-sm, 6px)",
            border: "1px solid var(--border-default, #2C2A4A)",
            overflow: "hidden",
          }}
        >
          <button
            aria-label="Grid view"
            aria-pressed={mode === "grid"}
            onClick={() => setMode("grid")}
            style={{
              width: 34,
              height: 30,
              display: "flex",
              alignItems: "center",
              justifyContent: "center",
              background: mode === "grid" ? "var(--brand-primary, #8B5CF6)" : "transparent",
              border: "none",
              color: mode === "grid" ? "#fff" : "var(--text-tertiary, #7B72A8)",
              fontSize: 14,
              cursor: "pointer",
            }}
          >
            <GridIcon />
          </button>
          <button
            aria-label="List view"
            aria-pressed={mode === "list"}
            onClick={() => setMode("list")}
            style={{
              width: 34,
              height: 30,
              display: "flex",
              alignItems: "center",
              justifyContent: "center",
              background: mode === "list" ? "var(--brand-primary, #8B5CF6)" : "transparent",
              border: "none",
              color: mode === "list" ? "#fff" : "var(--text-tertiary, #7B72A8)",
              fontSize: 14,
              cursor: "pointer",
            }}
          >
            <ListIcon />
          </button>
        </div>

        {/* Sort dropdown */}
        <SortControl />
      </div>
    </div>
  )
}

"use client"

import { useEffect } from "react"
import { useRefinementList } from "react-instantsearch"

/**
 * Headless component that observes the Algolia `game` facet refinement
 * and reports the active game code to a parent callback. Renders nothing.
 */
interface BrowsePageGameTrackerProps {
  onGameChange: (gameCode: string | null) => void
}

export function BrowsePageGameTracker({ onGameChange }: BrowsePageGameTrackerProps) {
  const { items } = useRefinementList({ attribute: "game" })
  const refined = items.filter((i) => i.isRefined)
  const activeCode = refined.length === 1 ? refined[0].value : null

  useEffect(() => {
    onGameChange(activeCode)
  }, [activeCode, onGameChange])

  return null
}

