              className="trending-card-link"
            >
              <style>{`
                .trending-card-link:hover { transform: translateY(-4px); }
                @media (max-width: 640px) {
                  .trending-card-link { width: 140px !important; }
                }
              `}</style>

              {/* Card image */}
              <div
                style={{
                  width: "100%",
                  aspectRatio: "5 / 7",
                  borderRadius: 12,
                  background: "var(--bg-surface-2, #21203A)",
                  border: "1px solid var(--border-default, #2C2A4A)",
                  marginBottom: 10,
                  overflow: "hidden",
                  position: "relative",
                }}
              >
                {card.image_url ? (
                  <img
                    src={card.image_url}
                    alt={card.name}
                    style={{ width: "100%", height: "100%", objectFit: "cover" }}
                  />
                ) : (
                  <CardArtPlaceholder />
                )}
              </div>

              {/* Card name */}
              <div
                style={{
                  fontFamily: "var(--font-heading, 'Barlow', sans-serif)",
                  fontSize: 13,
                  fontWeight: 600,
                  color: "var(--text-primary, #F0EEFF)",
                  marginBottom: 2,
                  whiteSpace: "nowrap",
                  overflow: "hidden",
                  textOverflow: "ellipsis",
                }}
              >
                {card.name}
              </div>

              {/* Set name */}
              <div
                style={{
                  fontSize: 12,
                  color: "var(--text-tertiary, #7B72A8)",
                  marginBottom: 6,
                  whiteSpace: "nowrap",
                  overflow: "hidden",
                  textOverflow: "ellipsis",
                }}
              >
                {card.set_name}
              </div>

              {/* Price + movement */}
              <div
                style={{
                  display: "flex",
                  alignItems: "center",
                  gap: 8,
                }}
              >
                <span
                  style={{
                    fontFamily: "var(--font-mono, 'DM Mono', monospace)",
                    fontSize: 14,
                    fontWeight: 500,
                    color: "var(--positive, #10B981)",
                  }}
                >
                  {formatPrice(card.price)}
                </span>
                <span
                  style={{
                    fontFamily: "var(--font-mono, 'DM Mono', monospace)",
                    fontSize: 11,
                    fontWeight: 500,
                    padding: "1px 5px",
                    borderRadius: 4,
                    color: isUp ? "var(--positive, #10B981)" : "var(--negative, #EF4444)",
                    background: isUp
                      ? "rgba(16, 185, 129, 0.12)"
                      : "rgba(239, 68, 68, 0.12)",
                  }}
                >
                  {isUp ? "+" : ""}
                  {card.movement}%
                </span>
              </div>
            </Link>
          )
        })}
      </div>
    </div>
  )
}

