import Link from "next/link"

/**
 * Full-width gradient banner encouraging users to become sellers.
 * Matches the wireframe seller-cta section.
 */
export function SellerCTA() {
  return (
    <div
      data-testid="seller-cta"
      style={{
        margin: "0 32px 48px",
        borderRadius: 20,
        padding: "56px 48px",
        background: "linear-gradient(135deg, var(--brand-primary, #8B5CF6), var(--brand-secondary, #FF7849))",
        textAlign: "center",
        position: "relative",
        overflow: "hidden",
      }}
    >
      {/* Decorative radial gradient circle at top-right */}
      <div
        aria-hidden="true"
        style={{
          position: "absolute",
          top: 0,
          right: -100,
          width: 400,
          height: 400,
          background: "radial-gradient(circle, rgba(255,255,255,0.08) 0%, transparent 60%)",
          pointerEvents: "none",
        }}
      />

      {/* Title */}
      <h2
        style={{
          fontFamily: "var(--font-display, 'Barlow Condensed', sans-serif)",
          fontWeight: 800,
          fontSize: 44,
          color: "white",
          marginBottom: 8,
          position: "relative",
          lineHeight: 1.1,
        }}
      >
        Join 10,000+ Players
      </h2>

      {/* Subtitle */}
      <p
        style={{
          fontSize: 16,
          color: "rgba(255, 255, 255, 0.85)",
          marginBottom: 28,
          position: "relative",
        }}
      >
        Start selling in minutes. No listing fees.
      </p>

      {/* CTA button */}
      <Link
        href="/sell"
        data-testid="seller-cta-button"
        style={{
          display: "inline-block",
          background: "white",
          color: "#18162A",
          fontFamily: "var(--font-heading, 'Barlow', sans-serif)",
          fontWeight: 700,
          fontSize: 15,
          padding: "14px 32px",
          borderRadius: 12,
          border: "none",
          cursor: "pointer",
          position: "relative",
          transition: "transform 0.15s, box-shadow 0.15s",
          textDecoration: "none",
        }}
        onMouseEnter={(e) => {
          e.currentTarget.style.transform = "translateY(-1px)"
          e.currentTarget.style.boxShadow = "0 8px 32px rgba(0,0,0,0.2)"
        }}
        onMouseLeave={(e) => {
          e.currentTarget.style.transform = "translateY(0)"
          e.currentTarget.style.boxShadow = "none"
        }}
      >
        Start Selling
      </Link>
    </div>
  )
}

