import { CardBrowsingPage } from '../CardBrowsingPage'

describe('CardBrowsingPage', () => {
  beforeEach(() => {
    vi.clearAllMocks()
  })

  it('renders the browse page with breadcrumbs', () => {
    render(<CardBrowsingPage />)
    expect(screen.getByTestId('browse-breadcrumbs')).toBeInTheDocument()
  })

  it('renders the game selector strip', () => {
    render(<CardBrowsingPage />)
    expect(screen.getByTestId('game-strip-desktop')).toBeInTheDocument()
  })

  it('renders category pills on desktop', () => {
    render(<CardBrowsingPage />)
    expect(screen.getByTestId('category-pills')).toBeInTheDocument()
  })

  it('renders popular sets carousel', () => {
    render(<CardBrowsingPage />)
    expect(screen.getByTestId('popular-sets-carousel')).toBeInTheDocument()
  })

  it('renders results bar', () => {
    render(<CardBrowsingPage />)
    expect(screen.getByTestId('results-bar')).toBeInTheDocument()
  })

  it('renders card search grid (sidebar + grid)', () => {
    render(<CardBrowsingPage />)
    expect(screen.getByTestId('card-search-grid')).toBeInTheDocument()
  })

  it('renders InstantSearchNext provider', () => {
    render(<CardBrowsingPage />)
    expect(screen.getByTestId('instant-search-provider')).toBeInTheDocument()
  })

  it('renders sections in correct wireframe order', () => {
    const { container } = render(<CardBrowsingPage />)
    const html = container.innerHTML

    // Section order: breadcrumbs → game strip → categories → popular sets → results bar → grid → trending → cta
    const breadcrumbsPos = html.indexOf('browse-breadcrumbs')
    const gameStripPos = html.indexOf('game-strip-desktop')
    const categoryPos = html.indexOf('category-pills')
    const setsPos = html.indexOf('popular-sets-carousel')
    const resultsBarPos = html.indexOf('results-bar')
    const gridPos = html.indexOf('card-search-grid')
    const trendingPos = html.indexOf('trending-strip')
    const ctaPos = html.indexOf('seller-cta')

    expect(breadcrumbsPos).toBeLessThan(gameStripPos)
    expect(gameStripPos).toBeLessThan(categoryPos)
    expect(categoryPos).toBeLessThan(setsPos)
    expect(setsPos).toBeLessThan(resultsBarPos)
    expect(resultsBarPos).toBeLessThan(gridPos)
    expect(gridPos).toBeLessThan(trendingPos)
    expect(trendingPos).toBeLessThan(ctaPos)
  })

  it('renders trending strip and seller CTA', () => {
    render(<CardBrowsingPage />)
    expect(screen.getByTestId('trending-strip')).toBeInTheDocument()
    expect(screen.getByTestId('seller-cta')).toBeInTheDocument()
  })

  it('renders all 5 game selector items', () => {
    render(<CardBrowsingPage />)
    expect(screen.getByTestId('game-strip-all')).toBeInTheDocument()
    expect(screen.getByTestId('game-strip-MTG')).toBeInTheDocument()
    expect(screen.getByTestId('game-strip-POKEMON')).toBeInTheDocument()
    expect(screen.getByTestId('game-strip-YUGIOH')).toBeInTheDocument()
    expect(screen.getByTestId('game-strip-OPTCG')).toBeInTheDocument()
  })

  it('uses design token classes — no hardcoded gray/blue', () => {
    const { container } = render(<CardBrowsingPage />)
    const html = container.innerHTML
    expect(html).not.toContain('bg-gray-100')
    expect(html).not.toContain('text-gray-700')
    expect(html).not.toContain('bg-blue-600')
    expect(html).not.toContain('bg-blue-100')
  })
})

import { render, screen, fireEvent } from '@testing-library/react'
import { describe, it, expect, vi, beforeEach } from 'vitest'
import React from 'react'

// ─── Mocks ────────────────────────────────────────────────────────────────────

const mockRefine = vi.fn()
let mockItems: Array<{ value: string; label: string; count: number; isRefined: boolean }> = []

vi.mock('react-instantsearch', () => ({
  useRefinementList: () => ({ items: mockItems, refine: mockRefine }),
}))

