import { GameSelectorStrip, GAME_STRIP_ITEMS } from '../GameSelectorStrip'

describe('GameSelectorStrip', () => {
  beforeEach(() => {
    vi.clearAllMocks()
    mockItems = [
      { value: 'MTG', label: 'MTG', count: 5280, isRefined: false },
      { value: 'POKEMON', label: 'POKEMON', count: 3820, isRefined: false },
      { value: 'YUGIOH', label: 'YUGIOH', count: 2140, isRefined: false },
      { value: 'OPTCG', label: 'OPTCG', count: 1160, isRefined: false },
    ]
    // Clear cookies
    document.cookie = 'sd_game_pref=; max-age=0; path=/'
  })

  it('renders 5 game items on desktop', () => {
    render(<GameSelectorStrip />)
    expect(screen.getByTestId('game-strip-all')).toBeInTheDocument()
    expect(screen.getByTestId('game-strip-MTG')).toBeInTheDocument()
    expect(screen.getByTestId('game-strip-POKEMON')).toBeInTheDocument()
    expect(screen.getByTestId('game-strip-YUGIOH')).toBeInTheDocument()
    expect(screen.getByTestId('game-strip-OPTCG')).toBeInTheDocument()
  })

  it('exports GAME_STRIP_ITEMS with 5 entries', () => {
    expect(GAME_STRIP_ITEMS).toHaveLength(5)
    expect(GAME_STRIP_ITEMS[0].code).toBeNull() // "All Games"
    expect(GAME_STRIP_ITEMS[1].code).toBe('MTG')
    expect(GAME_STRIP_ITEMS[2].code).toBe('POKEMON')
    expect(GAME_STRIP_ITEMS[3].code).toBe('YUGIOH')
    expect(GAME_STRIP_ITEMS[4].code).toBe('OPTCG')
  })

  it('displays game names from data', () => {
    render(<GameSelectorStrip />)
    expect(screen.getByText('All Games')).toBeInTheDocument()
    expect(screen.getByText('Magic: The Gathering')).toBeInTheDocument()
    expect(screen.getByText('Pokémon')).toBeInTheDocument()
    expect(screen.getByText('Yu-Gi-Oh!')).toBeInTheDocument()
    expect(screen.getByText('One Piece')).toBeInTheDocument()
  })

  it('shows "All Games" as active when no game is refined', () => {
    render(<GameSelectorStrip />)
    const allBtn = screen.getByTestId('game-strip-all')
    // No game refined = "All Games" is not explicitly active in the same way,
    // but aria-pressed should indicate it
    expect(allBtn).toHaveAttribute('aria-pressed', 'true')
  })

  it('shows a game as active when it is refined', () => {
    mockItems[0].isRefined = true // MTG refined
    render(<GameSelectorStrip />)
    const mtgBtn = screen.getByTestId('game-strip-MTG')
    expect(mtgBtn).toHaveAttribute('aria-pressed', 'true')
    const allBtn = screen.getByTestId('game-strip-all')
    expect(allBtn).toHaveAttribute('aria-pressed', 'false')
  })

  it('calls refine when clicking a game', () => {
    render(<GameSelectorStrip />)
    fireEvent.click(screen.getByTestId('game-strip-MTG'))
    expect(mockRefine).toHaveBeenCalledWith('MTG')
  })

  it('sets sd_game_pref cookie when clicking a game', () => {
    render(<GameSelectorStrip />)
    fireEvent.click(screen.getByTestId('game-strip-MTG'))
    expect(document.cookie).toContain('sd_game_pref=MTG')
  })

  it('clears cookie when clicking "All Games"', () => {
    document.cookie = 'sd_game_pref=MTG; path=/'
    render(<GameSelectorStrip />)
    fireEvent.click(screen.getByTestId('game-strip-all'))
    // Cookie should be cleared (max-age=0)
    expect(document.cookie).not.toContain('sd_game_pref=MTG')
  })

  it('renders mobile pill row', () => {
    render(<GameSelectorStrip />)
    expect(screen.getByTestId('game-strip-mobile')).toBeInTheDocument()
    expect(screen.getByTestId('game-pill-all')).toBeInTheDocument()
    expect(screen.getByTestId('game-pill-MTG')).toBeInTheDocument()
  })

  it('displays card counts from Algolia facets', () => {
    render(<GameSelectorStrip />)
    // MTG should show its count
    expect(screen.getAllByText('5,280 cards').length).toBeGreaterThanOrEqual(1)
  })

  it('each game strip item has a unique gradient background', () => {
    expect(new Set(GAME_STRIP_ITEMS.map(g => g.bgGradient)).size).toBe(5)
  })

  it('each game has correct border and glow colors', () => {
    const mtg = GAME_STRIP_ITEMS.find(g => g.code === 'MTG')!
    expect(mtg.borderColor).toContain('game-mtg')
    expect(mtg.glowColor).toContain('167, 139, 250')

    const pokemon = GAME_STRIP_ITEMS.find(g => g.code === 'POKEMON')!
    expect(pokemon.borderColor).toContain('game-pokemon')
  })
})

